module asyn_fifo
#(
    parameter WIDTH = 8,
    parameter DEPTH = 16
)
(
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata:
); 

    parameter WIDTH = 8;
    parameter DEPTH = 16;

    reg [3:0] waddr_bin; 
    reg [3:0] raddr_bin; 
    reg [3:0] wptr; 
    reg [3:0] rptr; 
    reg [3:0] wptr_buff; 
    reg [3:0] rptr_buff; 
    wire [3:0] wptr_syn; 
    wire [3:0] rptr_syn; 
    wire [3:0] wptr_gray; 
    wire [3:0] rptr_gray; 
    wire wfull_comb; 
    wire rempty_comb; 

    dual_port_RAM #(DEPTH, WIDTH) dual_port_ram (
        .wclk(wclk),
        .wenc(winc),
        .waddr(waddr_bin),
        .wdata(wdata),
        .rclk(rclk),
        .renc(rinc),
        .raddr(raddr_bin),
        .rdata(rdata)
    );

    always @(posedge wclk or negedge wrstn) begin
        if (~wrstn) begin
            waddr_bin <= 4'd0;
        end else if (winc) begin
            waddr_bin <= waddr_bin + 1;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (~rrstn) begin
            raddr_bin <= 4'd0;
        end else if (rinc) begin
            raddr_bin <= raddr_bin + 1;
        end
    end

    assign wptr_gray[3] = wptr[3];
    assign wptr_gray[2] = wptr[3] ^ wptr[2];
    assign wptr_gray[1] = wptr[2] ^ wptr[1];
    assign wptr_gray[0] = wptr[1] ^ wptr[0];
    assign rptr_gray[3] = rptr[3];
    assign rptr_gray[2] = rptr[3] ^ rptr[2];
    assign rptr_gray[1] = rptr[2] ^ rptr[1];
    assign rptr_gray[0] = rptr[1] ^ rptr[0];

    always @(posedge wclk or negedge wrstn) begin
        if (~wrstn) begin
            wptr_buff <= 4'd0;
        end else begin
            wptr_buff <= wptr_syn;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (~rrstn) begin
            rptr_buff <= 4'd0;
        end else begin
            rptr_buff <= rptr_syn;
        end
    end

    assign rptr_syn = rptr_buff;
    assign wptr_syn = wptr_buff;

    assign wfull_comb = (wptr == {~rptr_syn[3], rptr_syn[2:0]});
    assign rempty_comb = (rptr == wptr_syn);
    assign wfull = wfull_comb;
    assign rempty = rempty_comb;

    always @(posedge wclk or negedge wrstn) begin
        if (~wrstn) begin
            wptr <= 4'd0;
        end else begin
            if (winc && ~wfull_comb) begin
                wptr <= wptr + 1;
            end
        end
    end
    always @(posedge rclk or negedge rrstn) begin
        if (~rrstn) begin
            rptr <= 4'd0;
        end else begin
            if (rinc && ~rempty_comb) begin
                rptr <= rptr + 1;
            end
        end
    end
endmodule
